// STEP 1 -- PARSE PURSUE COMMAND v2
const fs = require('fs');
const raw = $input.first().json;
const body = raw.body || raw;
const rawTitle = String(body.title || body.opportunity || body.text || '').trim();
const source = String(body.source || 'manual').toLowerCase();
const kevinNote = String(body.note || body.kevin_note || '').trim();
const entityHint = String(body.entity || '').toUpperCase();
const beachheadHint = String(body.beachhead || '').toUpperCase();
// PATCH: preserve mission_path if passed by caller (dashboard openPursuit)
const missionPath = body.mission_path || body.missionPath || null;
let kaiContext = {};
try { kaiContext = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) {}
const resolveEntity = (title, hint) => {
  if (hint && ['FP','EAF','MONK','MULTI'].includes(hint)) return hint;
  const t = title.toLowerCase();
  if (t.includes('grant') || t.includes('workforce') || t.includes('nonprofit') || t.includes('earn') || t.includes('eaf') || t.includes('cako') || t.includes('fema preparedness') || t.includes('workforce')) return 'EAF';
  if (t.includes('sbir') || t.includes('monk') || t.includes('r&d') || t.includes('patent') || t.includes('licensing')) return 'MONK';
  if (t.includes('inspection') || t.includes('contract') || t.includes('consulting') || t.includes('bd') || t.includes('rfp') || t.includes('utility') || t.includes('bridge') || t.includes('dfr') || t.includes('police') || t.includes('medical supply')) return 'FP';
  return 'MULTI';
};
const resolveType = (title) => {
  const t = title.toLowerCase();
  if (t.includes('sbir') || t.includes('sttr')) return 'sbir';
  if (t.includes('grant') || t.includes('fema') || t.includes('earn') || t.includes('workforce')) return 'grant';
  if (t.includes('contract') || t.includes('rfp') || t.includes('inspection') || t.includes('dfr')) return 'contract';
  if (t.includes('consulting') || t.includes('advisory') || t.includes('omb m-26')) return 'consulting';
  if (t.includes('licensing') || t.includes('oem') || t.includes('partnership')) return 'licensing';
  if (t.includes('job') || t.includes('employment') || t.includes('ojt') || t.includes('position') || t.includes('hire')) return 'employment';
  return 'contract';
};
const entity = resolveEntity(rawTitle, entityHint);
const opportunityType = resolveType(rawTitle);
const triggerJordan = true;
const triggerIris = entity === 'EAF' || entity === 'MULTI';
const triggerAtlas = entity === 'MONK';
return [{ json: {
  title: rawTitle,
  source,
  kevinNote,
  entity,
  beachheadHint,
  opportunityType,
  triggerJordan,
  triggerIris,
  triggerAtlas,
  missionPath,
  timestamp: new Date().toISOString(),
  founderName: (kaiContext.founder || {}).name || 'Kevin Alexander Smith',
  founderCredentials: ((kaiContext.founder || {}).credentials || []).join(', ')
}}];

// STEP 2 -- UPSERT TO PIPELINE (v2 -- prevents duplicates)
// Uses Supabase upsert with on_conflict=title,entity
// If same title+entity already exists, updates status to pursuing
const https = require('https');
const input = $input.first().json;
const SUPABASE_URL = ($env.SUPABASE_URL || '').replace('https://','').replace('http://','');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY || '';
const record = {
  title: input.title,
  source: input.source,
  entity: input.entity,
  opportunity_type: input.opportunityType,
  beachhead: input.beachheadHint || null,
  status: 'pursuing',
  kevin_note: input.kevinNote || null,
  jordan_triggered: input.triggerJordan,
  iris_triggered: input.triggerIris,
  atlas_triggered: input.triggerAtlas,
  discovered_by_agent: 'Nova-Pursue v2',
  run_date: new Date().toISOString().slice(0,10)
};
let pipelineId = null;
let writeStatus = 'failed';
if (!SUPABASE_URL || !SUPABASE_KEY) {
  writeStatus = 'skipped -- missing Supabase credentials';
  return [{ json: { ...input, pipelineId, writeStatus } }];
}
try {
  const body = JSON.stringify(record);
  const result = await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: SUPABASE_URL,
      port: 443,
      path: '/rest/v1/pipeline',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Prefer': 'resolution=merge-duplicates,return=representation',
        'Content-Length': Buffer.byteLength(body)
      }
    }, (res) => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode, body: d })); });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
  if (result.status === 201 || result.status === 200) {
    writeStatus = 'saved';
    try { pipelineId = JSON.parse(result.body)[0]?.id || null; } catch(e) {}
  } else {
    writeStatus = 'error_' + result.status + ': ' + result.body.substring(0, 200);
  }
} catch(e) {
  writeStatus = 'error: ' + e.message;
}
return [{ json: { ...input, pipelineId, writeStatus } }];

// STEP 3 -- NOVA PURSUIT PLAN (new in v2)
const https = require('https');
const fs = require('fs');
const input = $input.first().json;
let kaiContext = {};
try { kaiContext = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) {}
const phase = kaiContext.phase || {};
const constraints = kaiContext.discovery_profile?.stage_constraints || {};
const constraintStr = Object.entries(constraints).filter(([k,v]) => v === true).map(([k]) => k).join(', ');
const deadlines = (kaiContext.deadlines || []).filter(d => !['COMPLETE','FILED','EXEMPT'].includes(d.status)).slice(0, 5).map(d => `${d.item} | Due: ${d.date} | ${d.status}`).join('\n');
const systemPrompt = `You are Nova, KAI-Netics Pursuit Orchestrator. When Kevin says to pursue something, you build the operational plan.\n\nFOUNDER: ${input.founderName} | ${input.founderCredentials}\nPHASE: ${phase.current}\nCONSTRAINTS: ${constraintStr || 'none'}\nACTIVE DEADLINES:\n${deadlines}\n\nReturn STRICT JSON only -- no markdown, no preamble:\n{\n  "mission_title": "string",\n  "entity": "FP | EAF | MONK | MULTI",\n  "opportunity_type": "string",\n  "mission_objective": "1 sentence",\n  "immediate_actions": ["action 1 -- specific with URL or contact", "action 2", "action 3"],\n  "jordan_task": "loi | capability_statement | sbir_narrative | capability_statement_and_loi",\n  "jordan_brief": "2-3 sentences telling Jordan exactly what to draft and why",\n  "iris_alert": "deadline or compliance flag for Iris to track, or null",\n  "blockers": ["any constraint flags"],\n  "timeline": "when this needs to be acted on",\n  "revenue_path": "how this becomes money for KAI-Netics",\n  "success_metric": "what does done look like"\n}`;
const userPrompt = `Build pursuit plan for: ${input.title}\n\nEntity: ${input.entity}\nType: ${input.opportunityType}\nKevin note: ${input.kevinNote || 'none'}\nToday: ${new Date().toLocaleDateString('en-US', { timeZone: 'America/New_York' })}\n\nReturn operational JSON only.`;
const requestBody = JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: 1000, system: systemPrompt, messages: [{ role: 'user', content: userPrompt }] });
const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.anthropic.com', port: 443, path: '/v1/messages', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'x-api-key': process.env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'Content-Length': Buffer.byteLength(requestBody) }
  }, (res) => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode, body: d })); });
  req.on('error', reject); req.write(requestBody); req.end();
});
let plan = {
  mission_title: input.title,
  entity: input.entity,
  opportunity_type: input.opportunityType,
  mission_objective: 'Pursue ' + input.title,
  immediate_actions: ['Review opportunity', 'Contact Jordan for draft', 'Set Iris deadline alert'],
  jordan_task: input.entity === 'EAF' ? 'loi' : input.entity === 'MONK' ? 'sbir_narrative' : 'capability_statement',
  jordan_brief: 'Draft initial outreach for ' + input.title,
  iris_alert: null,
  blockers: [],
  timeline: 'ASAP',
  revenue_path: 'TBD',
  success_metric: 'Draft submitted'
};
try {
  const rawText = JSON.parse(result.body)?.content?.[0]?.text || '';
  const clean = rawText.replace(/^```json\s*/,'').replace(/^```\s*/,'').replace(/\s*```$/,'').trim();
  try { plan = JSON.parse(clean); } catch(e) {
    const first = clean.indexOf('{'); const last = clean.lastIndexOf('}');
    if (first !== -1 && last > first) { try { plan = JSON.parse(clean.substring(first, last+1)); } catch(e2) {} }
  }
} catch(e) {}
const fs2 = require('fs');
const dateStr = new Date().toISOString().replace(/[:.]/g,'-').slice(0,19);
const planPath = `/data/Aidan_Outputs/Nova/Pursue_${dateStr}.json`;
fs2.mkdirSync('/data/Aidan_Outputs/Nova', { recursive: true });
fs2.writeFileSync(planPath, JSON.stringify({ meta: { title: input.title, entity: input.entity, timestamp: input.timestamp, pipelineId: input.pipelineId, writeStatus: input.writeStatus, missionPath: input.missionPath }, plan }, null, 2), 'utf8');
return [{ json: { ...input, plan, planPath, jordanTask: plan.jordan_task, jordanBrief: plan.jordan_brief, irisAlert: plan.iris_alert, immediateActions: plan.immediate_actions, revenuePath: plan.revenue_path } }];

// STEP 4 -- FIRE DOWNSTREAM AGENTS
// PATCH v2.1: pass mission_path to Jordan so jordan_callback can write chain update
const http = require('http');
const input = $input.first().json;
const fireWebhook = async (path, payload) => {
  const bodyStr = JSON.stringify(payload);
  const opts = { hostname: 'host.docker.internal', port: 5678, path, method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr) } };
  return new Promise(r => { const req = http.request(opts, res => { res.on('data',()=>{}); res.on('end',r); }); req.on('error',r); req.write(bodyStr); req.end(); });
};
const jordanPayload = {
  trigger: 'pursue_command',
  pipeline_id: input.pipelineId,
  opportunity: input.title,
  entity: input.entity,
  opportunity_type: input.opportunityType,
  task: input.jordanTask || 'capability_statement',
  kevin_note: input.kevinNote || '',
  jordan_brief: input.jordanBrief || '',
  founder_credentials: input.founderCredentials,
  mission_path: input.missionPath || null
};
await fireWebhook('/webhook/grant-writer', jordanPayload);
if (input.triggerIris && input.irisAlert) {
  await fireWebhook('/webhook/iris-monitor', {
    trigger: 'pursue_command',
    pipeline_id: input.pipelineId,
    opportunity: input.title,
    entity: input.entity,
    note: input.irisAlert
  });
}
if (input.triggerAtlas) {
  await fireWebhook('/webhook/atlas-architect', {
    command: 'Pipeline MONK prep',
    detail: input.title + ' -- SBIR/R&D technical narrative needed',
    pipeline_id: input.pipelineId
  });
}
return [{ json: { ...input, agentsFired: ['Jordan', ...(input.triggerIris && input.irisAlert ? ['Iris'] : []), ...(input.triggerAtlas ? ['Atlas'] : [])] } }];

// STEP 5 -- CONFIRM TO KEVIN VIA WHATSAPP
const http = require('http');
const input = $input.first().json;
const entityLabel = { 'FP': 'For-Profit', 'EAF': 'Nonprofit', 'MONK': 'R&D/IP', 'MULTI': 'Multi-entity' }[input.entity] || input.entity;
const taskLabel = {
  'loi': 'LOI draft',
  'capability_statement': 'capability statement',
  'sbir_narrative': 'SBIR narrative',
  'capability_statement_and_loi': 'cap statement + LOI'
}[input.jordanTask] || 'draft';
const dbIcon = input.writeStatus === 'saved' ? '✓' : '⚠';
const agents = (input.agentsFired || []).join(' + ');
const actions = (input.immediateActions || []).slice(0, 3).map((a, i) => `${i+1}. ${a.substring(0, 120)}`).join('\n');
let msg = `NOVA PURSUIT CONFIRMED\n\n`;
msg += `Mission: ${input.title}\n`;
msg += `Entity: ${entityLabel} [${input.entity}]\n`;
msg += `Type: ${input.opportunityType}\n`;
if (input.kevinNote) msg += `Your note: ${input.kevinNote}\n`;
msg += `\nPipeline: ${dbIcon} ${input.writeStatus}\n`;
msg += `Agents fired: ${agents}\n`;
msg += `Jordan drafting: ${taskLabel}\n`;
msg += `Mission chain: will update on Jordan complete\n`;
if (input.revenuePath && input.revenuePath !== 'TBD') msg += `\nRevenue path: ${input.revenuePath}\n`;
if (actions) msg += `\nImmediate actions:\n${actions}\n`;
msg += `\nDraft ready ~60 seconds.\nCheck Dashboard pipeline tab.`;
const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: msg } });
const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) } };
await new Promise(r => { const req = http.request(opts, res => { res.on('data',()=>{}); res.on('end',r); }); req.on('error',r); req.write(msgBody); req.end(); });
const cbBody = JSON.stringify({ agent: 'Nova', subagent: 'Pursue v2.1', opportunity: input.title, entity: input.entity, pipelineId: input.pipelineId, writeStatus: input.writeStatus, agentsFired: input.agentsFired, missionPath: input.missionPath, timestamp: new Date().toISOString() });
const cbOpts = { hostname: 'host.docker.internal', port: 5678, path: '/webhook/aidan-callback', method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) } };
const cbReq = http.request(cbOpts, res => { res.on('data',()=>{}); res.on('end',()=>{}); }); cbReq.on('error',()=>{}); cbReq.write(cbBody); cbReq.end();
return [{ json: { success: true, opportunity: input.title, entity: input.entity, pipelineId: input.pipelineId, agentsFired: input.agentsFired } }];
